fun solve(nums: Array<Long>, k: Long): Long {
    nums.sort()
    val n = nums.size
    var minRemove = n - 1 // Worst case, remove all but one

    for (i in 0 until n) {
        // Check if the subarray from i to n-1 is balanced
        if (nums[n - 1] <= nums[i] * k) {
            minRemove = min(minRemove, n - i - 1)
            break // Since array is sorted, further elements will have larger max, so no need to check
        }
    }

    return minRemove
}
